1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	// Main items are insured individually at their base premium.
7	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	// Components are grouped by type; exactly BLOCK_SIZE alike components
15	// form a "block" with a fixed base premium instead of per-item pricing.
16	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
17	  rune: 25,
18	};
19	
20	const isComponent = (itemType: string): boolean =>
21	  itemType in COMPONENT_BASE_PREMIUMS;
22	
23	const countByType = (items: { type: string }[]): Record<string, number> =>
24	  items.reduce<Record<string, number>>((counts, item) => {
25	    counts[item.type] = (counts[item.type] ?? 0) + 1;
26	    return counts;
27	  }, {});
28	
29	const componentGroupPremium = (componentType: string, count: number): number => {
30	  const perItem = COMPONENT_BASE_PREMIUMS[componentType];
31	  return count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * perItem;
32	};
33	
34	const computeBasePremium = (items: { type: string }[]): number => {
35	  const counts = countByType(items);
36	  return Object.entries(counts).reduce((total, [type, count]) => {
37	    if (isComponent(type)) {
38	      return total + componentGroupPremium(type, count);
39	    }
40	    return total + count * (MAIN_ITEM_BASE_PREMIUMS[type] ?? 0);
41	  }, 0);
42	};
43	
44	export const runScenario = (scenario: any): unknown => {
45	  const items = scenario?.steps?.[0]?.items ?? [];
46	  const basePremium = computeBasePremium(items);
47	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
48	  const premium = basePremium + surcharge + PROCESSING_FEE;
49	  return { results: [{ premium }] };
50	};
